content:
{
  "sentences": [
    {
      "text": "那個人長得很高，也很瘦。",
      "pinyin": "Nà ge rén zhǎng de hěn gāo, yě hěn shòu.",
      "pinyin_numeric": "na4 ge4 ren2 zhang3 de5 hen3 gao1, ye3 hen3 shou4",
      "translation_en": "That person is very tall and also very thin.",
      "translation_ko": "그 사람은 키가 매우 크고, 또한 매우 날씬해요."
    },
    {
      "text": "我妹妹的個性很活潑，也很友善。",
      "pinyin": "Wǒ mèimei de gèxìng hěn huópō, yě hěn yǒushàn.",
      "pinyin_numeric": "wo3 mei4mei5 de5 ge4xing4 hen3 huo2po1, ye3 hen3 you3shan4",
      "translation_en": "My younger sister's personality is very lively and also very friendly.",
      "translation_ko": "제 여동생의 성격은 매우 활발하고, 또한 매우 친절해요."
    },
    {
      "text": "他戴眼鏡，看起來很聰明。",
      "pinyin": "Tā dài yǎnjìng, kàn qǐlái hěn cōngmíng.",
      "pinyin_numeric": "ta1 dai4 yan3jing4, kan4 qi3lai2 hen3 cong1ming2",
      "translation_en": "He wears glasses and looks very smart.",
      "translation_ko": "그는 안경을 쓰고 있어서 매우 똑똑해 보여요."
    },
    {
      "text": "我哥哥很幽默，他說話很有趣。",
      "pinyin": "Wǒ gēge hěn yōumò, tā shuōhuà hěn yǒuqù.",
      "pinyin_numeric": "wo3 ge1ge5 hen3 you1mo4, ta1 shuo1hua4 hen3 you3qu4",
      "translation_en": "My older brother is very humorous; his speech is very interesting.",
      "translation_ko": "제 오빠는 매우 유머러스해요. 그의 말은 매우 재미있어요."
    },
    {
      "text": "那個女生穿著白色的衣服，很漂亮。",
      "pinyin": "Nà ge nǚshēng chuān zhe báisè de yīfú, hěn piàoliang.",
      "pinyin_numeric": "na4 ge4 nü3sheng1 chuan1 zhe5 bai2se4 de5 yi1fu2, hen3 piao4liang5",
      "translation_en": "That girl is wearing white clothes and is very pretty.",
      "translation_ko": "그 여학생은 하얀 옷을 입고 있어서 매우 예뻐요."
    },
    {
      "text": "他長得很帥，個性也很溫柔。",
      "pinyin": "Tā zhǎng de hěn shuài, gèxìng yě hěn wēnróu.",
      "pinyin_numeric": "ta1 zhang3 de5 hen3 shuai4, ge4xing4 ye3 hen3 wen1rou2",
      "translation_en": "He is very handsome, and his personality is also very gentle.",
      "translation_ko": "그는 매우 잘생겼고, 성격도 매우 부드러워요."
    },
    {
      "text": "我認識一個很害羞的人，他不喜歡說話。",
      "pinyin": "Wǒ rènshi yī ge hěn hàixiū de rén, tā bù xǐhuān shuōhuà.",
      "pinyin_numeric": "wo3 ren4shi5 yi1 ge4 hen3 hai4xiu1 de5 ren2, ta1 bu4 xi3huan5 shuo1hua4",
      "translation_en": "I know a very shy person; he doesn't like to talk.",
      "translation_ko": "저는 매우 수줍은 사람을 알아요. 그는 말하는 것을 좋아하지 않아요."
    },
    {
      "text": "那個人的頭髮很長，眼睛很大。",
      "pinyin": "Nà ge rén de tóufa hěn cháng, yǎnjīng hěn dà.",
      "pinyin_numeric": "na4 ge4 ren2 de5 tou2fa5 hen3 chang2, yan3jing1 hen3 da4",
      "translation_en": "That person has long hair and big eyes.",
      "translation_ko": "그 사람은 머리카락이 매우 길고, 눈이 매우 커요."
    },
    {
      "text": "聽說他很認真，工作也很努力。",
      "pinyin": "Tīngshuō tā hěn rènzhēn, gōngzuò yě hěn nǔlì.",
      "pinyin_numeric": "ting1shuo1 ta1 hen3 ren4zhen1, gong1zuo4 ye3 hen3 nu3li4",
      "translation_en": "I heard he is very serious and also works very hard.",
      "translation_ko": "그는 매우 진지하고, 일도 매우 열심히 한다고 들었어요."
    },
    {
      "text": "我朋友很大方，他請我喝咖啡。",
      "pinyin": "Wǒ péngyou hěn dàfāng, tā qǐng wǒ hē kāfēi.",
      "pinyin_numeric": "wo3 peng2you5 hen3 da4fang1, ta1 qing3 wo3 he1 ka1fei1",
      "translation_en": "My friend is very generous; he treated me to coffee.",
      "translation_ko": "제 친구는 매우 대범해요. 그가 저에게 커피를 사줬어요."
    }
  ]
}
